/**
 * @param {string} s
 * @return {string}
 */
function solve(s) {
    const vowels = new Set(['a', 'e', 'i', 'o', 'u']);
    const n = s.length;

    // 1. Record initial positions and frequencies of vowels
    const vowelInfo = new Map(); // Stores {vowel: {count: number, firstIndex: number}}
    const firstAppearance = new Map(); // Stores {vowel: index}

    for (let i = 0; i < n; i++) {
        const char = s[i];
        if (vowels.has(char)) {
            if (!vowelInfo.has(char)) {
                vowelInfo.set(char, { count: 0, firstIndex: i });
                firstAppearance.set(char, i);
            }
            vowelInfo.get(char).count++;
        }
    }

    // 2. Get a list of all unique vowels present and prepare for sorting
    let uniqueVowels = Array.from(vowelInfo.keys());

    // 3. Define the custom sorting logic
    // Criteria:
    // 1. Descending order of frequency (count)
    // 2. Ascending order of first appearance index (firstIndex) for ties
    uniqueVowels.sort((a, b) => {
        const infoA = vowelInfo.get(a);
        const infoB = vowelInfo.get(b);

        // Compare frequencies (non-increasing, so b - a for descending)
        if (infoB.count !== infoA.count) {
            return infoB.count - infoA.count;
        }
        // If frequencies are equal, compare first appearance index (non-decreasing, so a - b for ascending)
        return infoA.firstIndex - infoB.firstIndex;
    });

    // 4. Create the sorted sequence of all vowels
    const sortedVowels = [];
    for (const vowel of uniqueVowels) {
        const count = vowelInfo.get(vowel).count;
        for (let i = 0; i < count; i++) {
            sortedVowels.push(vowel);
        }
    }

    // 5. Rebuild the string
    // We need to place the characters from sortedVowels back into the original vowel positions.
    const resultArray = Array(n);
    let sortedVowelIndex = 0;

    for (let i = 0; i < n; i++) {
        const char = s[i];
        if (vowels.has(char)) {
            // This position was a vowel, replace it with the next vowel from the sorted sequence
            resultArray[i] = sortedVowels[sortedVowelIndex];
            sortedVowelIndex++;
        } else {
            // Consonant, keep it as is
            resultArray[i] = char;
        }
    }

    return resultArray.join('');
}
